css:
@import url("_global_style.css");

.mermaid-out {
  display: flex;
  justify-content: center;
  overflow-x: auto;
}

.mermaid-out svg {
  max-width: 100%;
  height: auto;
}

.mermaid-src {
  position: absolute;
  left: -9999px;
  top: 0;
  visibility: hidden;
  white-space: pre-wrap;
  margin: 0;
}

.mermaid-err {
  text-align: left;
  font-size: 0.85em;
  white-space: pre-wrap;
  color: #c0392b;
  max-width: 100%;
}

.nightMode .mermaid-err {
  color: #e74c3c;
}
